#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id directly
        stream << packet_id;

        // Serialize username with prefix (length prefix)
        stream << username;

        // Serialize scores with prefix (count first, then elements)
        stream << hexi::prefixed(scores);

        // Serialize metadata as null-terminated string
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create an empty vector as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor with the empty vector
    hexi::buffer_adaptor adaptor(buffer);

    // Call packet.serialise with the adaptor
    packet.serialise(adaptor);

    // Return the vector containing the serialized data
    return buffer;
}
```

## Explanation:

1. **Serialization Method (`serialise`)**:
   - `packet_id`: Serialized directly using `stream << packet_id` since it's a POD type
   - `username`: Uses the default string serialization which adds a length prefix
   - `scores`: Uses `hexi::prefixed(scores)` to first write the count (converted to little-endian) followed by the vector elements
   - `metadata`: Uses `hexi::null_terminated(metadata)` to write the string followed by a null terminator

2. **Serialization Function (`serialize_packet`)**:
   - Creates an empty `std::vector<uint8_t>` as the underlying buffer
   - Wraps the vector with `hexi::buffer_adaptor`
   - Calls the packet's `serialise` method with the adaptor
   - Returns the populated vector containing the serialized binary data

The implementation follows the Hexi library conventions as shown in the reference materials, using the appropriate adaptors for different data types and ensuring proper serialization format.

