```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a hexi::static_buffer from the input span
    hexi::static_buffer<uint8_t, buffer.size()> buffer_wrapper(buffer.data(), buffer.size());

    MessageHeader header;

    // Read message_type (uint16_t) from the buffer
    buffer_wrapper.read(&header.message_type, sizeof(uint16_t));

    // Read body_length (uint32_t) from the buffer
    buffer_wrapper.read(&header.body_length, sizeof(uint32_t));

    // Skip the body_data using skip() with body_length
    buffer_wrapper.skip(header.body_length);

    // Read footer (uint32_t) from the buffer
    buffer_wrapper.read(&header.footer, sizeof(uint32_t));

    return header;
}
```

## Explanation:

